import React, { useState, useEffect } from "react";
import "./App.css";

function App() {
  const [html, setHtml] = useState(localStorage.getItem("html") || "");
  const [css, setCss] = useState(localStorage.getItem("css") || "");
  const [js, setJs] = useState(localStorage.getItem("js") || "");

  useEffect(() => {
    localStorage.setItem("html", html);
    localStorage.setItem("css", css);
    localStorage.setItem("js", js);
  }, [html, css, js]);

  const output = `
    <html>
      <style>${css}</style>
      <body>
        ${html}
        <script>${js}<\/script>
      </body>
    </html>
  `;

  return (
    <div className="app">
      <h1>🔥 CodeSnip Pro</h1>

      <div className="editor">
        <div>
          <h3>HTML</h3>
          <textarea value={html} onChange={(e) => setHtml(e.target.value)} />
        </div>

        <div>
          <h3>CSS</h3>
          <textarea value={css} onChange={(e) => setCss(e.target.value)} />
        </div>

        <div>
          <h3>JS</h3>
          <textarea value={js} onChange={(e) => setJs(e.target.value)} />
        </div>
      </div>

      <h2>Live Preview</h2>

      <iframe
        srcDoc={output}
        title="output"
        sandbox="allow-scripts"
        frameBorder="0"
        width="100%"
        height="300px"
      />
    </div>
  );
}

export default App;
